// 验证和解析输入数据
const inputData = $input.first().json;

// 必需字段验证
const requiredFields = ['currentLevel', 'targetGoal', 'availableHoursPerWeek'];
const missingFields = requiredFields.filter(field => !inputData[field]);

if (missingFields.length > 0) {
  throw new Error(`缺少必需字段：${missingFields.join(', ')}`);
}

// 数据清理和标准化
const cleanedData = {
  currentLevel: inputData.currentLevel.toLowerCase(),
  targetGoal: inputData.targetGoal.trim(),
  availableHoursPerWeek: parseInt(inputData.availableHoursPerWeek),
  preferredLearningStyle: inputData.preferredLearningStyle || 'mixed',
  priorExperience: inputData.priorExperience || [],
  deadline: inputData.deadline || null,
  budget: inputData.budget || 'free'
};

// 学习级别映射
const levelMapping = {
  'beginner': { level: 1, name: '初学者', duration: '12 周' },
  'intermediate': { level: 2, name: '中级', duration: '8 周' },
  'advanced': { level: 3, name: '高级', duration: '4 周' }
};

cleanedData.levelInfo = levelMapping[cleanedData.currentLevel] || levelMapping['beginner'];

return {
  json: {
    status: 'validated',
    userData: cleanedData,
    timestamp: new Date().toISOString()
  }
};

// 解析 AI 生成的学习路径并添加元数据
const aiResponse = $input.first().json.output;
const userData = $('数据验证与处理').first().json.userData;

// 解析路径数据（如果 AI 返回的是字符串，则解析 JSON）
let learningPath = typeof aiResponse === 'string' 
  ? JSON.parse(aiResponse) 
  : aiResponse;

// 添加元数据
const enrichedPath = {
  ...learningPath,
  metadata: {
    generatedAt: new Date().toISOString(),
    userId: userData.userId || 'anonymous',
    pathVersion: '1.0',
    aiModel: 'gpt-4o'
  },
  learnerProfile: {
    currentLevel: userData.currentLevel,
    targetGoal: userData.targetGoal,
    availableHoursPerWeek: userData.availableHoursPerWeek,
    learningStyle: userData.preferredLearningStyle
  },
  progress: {
    currentPhase: 0,
    completedTopics: [],
    overallProgress: 0,
    startDate: null,
    estimatedEndDate: null
  }
};

// 计算预估结束日期
if (userData.deadline) {
  enrichedPath.progress.estimatedEndDate = new Date(userData.deadline).toISOString();
} else {
  const weeks = parseInt(learningPath.totalDuration) || 12;
  const endDate = new Date();
  endDate.setDate(endDate.getDate() + (weeks * 7));
  enrichedPath.progress.estimatedEndDate = endDate.toISOString();
}

return {
  json: {
    status: 'success',
    learningPath: enrichedPath,
    message: '学习路径生成成功'
  }
};

// 错误处理
const error = $input.first().json;

return {
  json: {
    status: 'error',
    error: {
      message: error.message || '未知错误',
      timestamp: new Date().toISOString(),
      suggestion: '请检查输入数据格式，确保包含所有必需字段'
    }
  }
};
